"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[4079],{3105(e,n,t){t.r(n),t.d(n,{assets:()=>d,contentTitle:()=>s,default:()=>c,frontMatter:()=>o,metadata:()=>r,toc:()=>h});var i=t(4848),a=t(8453);const o={},s="Chapter Eleven: A Love Letter to Gamers \u2014 Sega's Sacrifice and Nintendo's Walled Garden",r={id:"GameVictory/\u7b2c\u5341\u4e00\u7ae0_\u7d66\u904a\u6232\u73a9\u5bb6\u7684\u60c5\u66f8_v4",title:"Chapter Eleven: A Love Letter to Gamers \u2014 Sega's Sacrifice and Nintendo's Walled Garden",description:"January 31, 2001. Sega held a press conference in Tokyo.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u7b2c\u5341\u4e00\u7ae0_\u7d66\u904a\u6232\u73a9\u5bb6\u7684\u60c5\u66f8_v4.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u7b2c\u5341\u4e00\u7ae0_\u7d66\u904a\u6232\u73a9\u5bb6\u7684\u60c5\u66f8_v4",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u5341\u4e00\u7ae0_\u7d66\u904a\u6232\u73a9\u5bb6\u7684\u60c5\u66f8_v4",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 10: The Last Lifeline \u2014 When the Giants Personally Tear Down Their Own Stress Test Arenas",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u5341\u7ae0_\u6700\u5f8c\u4e00\u6839\u6551\u547d\u7a3b\u8349_v2"},next:{title:"Final Chapter: Games Are the Future (v5b)",permalink:"/MythogenEngine/en/docs/GameVictory/\u7d42\u7ae0_\u904a\u6232\u5373\u672a\u4f86_v5b"}},d={},h=[{value:"I. Autopsy",id:"i-autopsy",level:2},{value:"II. Iwata&#39;s Arithmetic",id:"ii-iwatas-arithmetic",level:2},{value:"III. The Cost of Not Fighting",id:"iii-the-cost-of-not-fighting",level:2},{value:"IV. The Island",id:"iv-the-island",level:2},{value:"V. NS2: A Crack in the Island",id:"v-ns2-a-crack-in-the-island",level:2},{value:"VI. Closing Arguments",id:"vi-closing-arguments",level:2},{value:"VII. The Spoils Are Still Being Divided",id:"vii-the-spoils-are-still-being-divided",level:2}];function l(e){const n={em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",img:"img",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"chapter-eleven-a-love-letter-to-gamers--segas-sacrifice-and-nintendos-walled-garden",children:"Chapter Eleven: A Love Letter to Gamers \u2014 Sega's Sacrifice and Nintendo's Walled Garden"})}),"\n",(0,i.jsx)(n.p,{children:"January 31, 2001. Sega held a press conference in Tokyo."}),"\n",(0,i.jsx)(n.p,{children:"President Shoichiro Irimajiri stood at the podium and announced the discontinuation of the Dreamcast. Sega was exiting the console hardware market. A company that had been building game consoles since the SG-1000 in 1983 \u2014 through the glory days of the Mega Drive, the bitter struggle of the Saturn, the final stand of the Dreamcast \u2014 was leaving the hardware battlefield forever."}),"\n",(0,i.jsxs)(n.p,{children:["The press conference was short. Irimajiri's words were restrained. But that evening, in the game shops of Akihabara, clerks moved the Dreamcast display cases to the corners. On 2ch forums, die-hard fans wrote eulogies. Someone quoted a line from ",(0,i.jsx)(n.em,{children:"Shenmue"}),': "\u3044\u3064\u304b\u5fc5\u305a\u3001\u3053\u306e\u9053\u3092\u3002" (',(0,i.jsx)(n.em,{children:"Someday, I will walk this road to its end."}),")"]}),"\n",(0,i.jsx)(n.p,{children:"The company was dead. But what it had done before dying \u2014 that $5 million lifeline described in Chapter Four, which kept NVIDIA alive past 1996 and ultimately grew into a $5 trillion AI monopoly \u2014 looks staggeringly heavy in retrospect, twenty-five years later."}),"\n",(0,i.jsx)(n.p,{children:"After Sega fell, only three players remained in the console market: Sony, Microsoft, and Nintendo. The first two marched down the road described in the preceding ten chapters \u2014 the compute arms race, platform lock-in, the Wall Street numbers game. The third took an entirely different path."}),"\n",(0,i.jsx)(n.p,{children:"But before we tell Nintendo's story, we need to finish Sega's autopsy. Because its cause of death was far more complicated than \"too good at technology.\""}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"i-autopsy",children:"I. Autopsy"}),"\n",(0,i.jsx)(n.p,{children:"To understand why Sega died, you first have to understand what Sega was."}),"\n",(0,i.jsx)(n.p,{children:'Sega was not Nintendo. Nintendo came from toys \u2014 hanafuda cards, playing cards, and only then electronic games. Nintendo\'s DNA was "fun." Its graphics never needed to be the best; they only needed to serve gameplay.'}),"\n",(0,i.jsxs)(n.p,{children:["Sega came from arcades. Its roots were in those machines that cost hundreds of thousands of yen each \u2014 hydraulic seats, wrap-around screens, sixty frames per second of real-time 3D without a single dropped frame. Sega's internal development team AM2, led by Yu Suzuki, had been doing something since the 1980s that Nintendo had never attempted: ",(0,i.jsx)(n.strong,{children:"pushing both hardware and experience to their absolute limits simultaneously."})]}),"\n",(0,i.jsxs)(n.p,{children:["1986: ",(0,i.jsx)(n.em,{children:"OutRun"}),". Super Scaler technology used high-speed sprite scaling to simulate 3D depth \u2014 effects that home consoles of the era couldn't even dream of. The hydraulic cabinet tilted with the screen, letting your body feel the centrifugal force of each turn. Sega called this design philosophy ",(0,i.jsx)(n.em,{children:"taikan"}),' \u2014 "bodily sensation."']}),"\n",(0,i.jsxs)(n.p,{children:["1993: ",(0,i.jsx)(n.em,{children:"Virtua Fighter"}),". The world's first fully 3D fighting game. Model 1 arcade board, real-time polygon rendering at sixty frames per second. In an era when ",(0,i.jsx)(n.em,{children:"Street Fighter II"})," had defined the fighting genre in 2D, AM2 leaped straight into 3D \u2014 not to show off, but because Suzuki believed three-dimensional space could achieve a depth and authenticity that 2D never could."]}),"\n",(0,i.jsxs)(n.p,{children:["1994: ",(0,i.jsx)(n.em,{children:"Daytona USA"}),". Model 2 board \u2014 custom hardware co-developed with GE Aerospace, a full generation faster than any home console. Eight linked cabinets for multiplayer racing, high-speed texture mapping, physically modeled engine roar and tire friction. This wasn't a racing game. It was an immersion device that made you forget you were sitting in an arcade."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:'Sega never pursued "best graphics" or "best gameplay" in isolation. It pursued both pushed to the limit simultaneously \u2014 using the most cutting-edge hardware to create experiences that the body and senses could not refuse.'})," This pursuit didn't exist in Nintendo's DNA. It didn't exist in the spreadsheet logic of Sony and Microsoft that came later. Sega was the closest thing to a craftsman that the platform-holder world has ever seen."]}),"\n",(0,i.jsx)(n.p,{children:"But the craftsman died. Three wounds killed it."}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"The first wound was self-inflicted."})," Before the Dreamcast, Sega had launched three pieces of hardware in five years \u2014 the Mega CD, the 32X, and the Saturn \u2014 each requiring its own game development ecosystem, its own supply chain, its own marketing budget. The Saturn's dual-CPU architecture drove third-party developers mad \u2014 only a team like AM2, coding from bare metal, could wring full performance from it. By the time Dreamcast launched, Sega's finances were hemorrhaging and developer trust was evaporating."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"The second wound was Sony's killing stroke."})," At the first E3 in 1995, Sega announced the Saturn was available immediately in North America at $399 \u2014 a gamble to seize first-mover advantage. Sony's response is the most famous single blow in gaming history: SCEA president Steve Race walked onstage, dropped his prepared remarks, said one word \u2014 \"$299\" \u2014 and walked off. A hundred-dollar price gap killed Saturn's momentum in North America in a single second. But Sony's killing move went beyond price. Ken Kutaragi's team had been touring game studios worldwide since 1994, carrying PlayStation 3D demos, promising low-cost CD manufacturing (an order of magnitude cheaper than cartridges) and a streamlined approval process. The result: Square pulled ",(0,i.jsx)(n.em,{children:"Final Fantasy VII"})," from Nintendo's camp and gave it to PlayStation. Capcom and Konami followed. ",(0,i.jsx)(n.strong,{children:"Sony didn't steal market share \u2014 it stole third-party exclusives."})," In an industry where a console lives or dies by its software lineup, losing third parties means losing everything."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"The third wound was the PS2."}),' March 2000. The launch covered in Chapter Three \u2014 Kutaragi standing onstage with Emotion Engine floating-point specs, positioning the PS2 as "the home computer of the twenty-first century." PS2 sold over ten million units in its first year. Dreamcast went from cliff-edge sales decline to discontinuation in under two years.']}),"\n",(0,i.jsx)(n.p,{children:"Three wounds combined: self-inflicted hardware fragmentation consuming finances and developer trust; Sony's tactical marketing stealing the third-party lineup; PS2's overwhelming installed base sealing the last exit."}),"\n",(0,i.jsx)(n.p,{children:"Sega's leadership did a calculation. Continue making hardware, lose hundreds of millions per year. Exit hardware and become a pure software company \u2014 at least survive."}),"\n",(0,i.jsxs)(n.p,{children:["Yu Suzuki built ",(0,i.jsx)(n.em,{children:"Shenmue"})," on the Dreamcast \u2014 development cost was never officially confirmed, but industry estimates range from $47 million to $70 million. ",(0,i.jsx)(n.em,{children:"Shenmue"})," had a dynamic day-night weather system, NPCs with independent schedules, convenience stores you could walk into, arcade machines you could play. In an era when 3D games were just learning to walk, Suzuki built an entire virtual town. The game was the ultimate expression of Sega's ",(0,i.jsx)(n.em,{children:"taikan"})," philosophy \u2014 and its final elegy."]}),"\n",(0,i.jsxs)(n.p,{children:["Sega's exit from the console hardware market sent a signal across the global gaming industry: ",(0,i.jsx)(n.strong,{children:"If even Sega \u2014 a company with top-tier arcade technology, top-tier game development capability, and a willingness to pursue perfection regardless of cost \u2014 couldn't hold on, then the lesson for anyone thinking about making console hardware was simple: either be too big to fail, or don't enter."})]}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"ii-iwatas-arithmetic",children:"II. Iwata's Arithmetic"}),"\n",(0,i.jsx)(n.p,{children:"May 31, 2002. Satoru Iwata became Nintendo's fourth president. Forty-two years old. His predecessor Hiroshi Yamauchi had retired and handpicked this programmer from HAL Laboratory \u2014 not a businessman, not a marketer \u2014 to lead a century-old company."}),"\n",(0,i.jsx)(n.p,{children:'When Iwata took over, Nintendo was being taught a lesson by GameCube\'s failure. GameCube carried a custom IBM PowerPC CPU codenamed "Gekko" and an ATI GPU codenamed "Flipper" \u2014 performance roughly on par with the PS2 and Xbox. Nintendo had earnestly fought a head-on specs war against Sony and Microsoft.'}),"\n",(0,i.jsx)(n.p,{children:"The result: GameCube sold 21.74 million units worldwide. PS2 sold 155 million. Xbox sold 24 million. GameCube finished last among the three \u2014 and not by a small margin."}),"\n",(0,i.jsx)(n.p,{children:"Iwata was not the kind of person to be paralyzed by failure. He was the kind of person who reached for a calculator."}),"\n",(0,i.jsx)(n.p,{children:"He did the math."}),"\n",(0,i.jsx)(n.p,{children:"The Emotion Engine's R&D cost ran into the hundreds of millions. Sony lost money on every PS2 sold in the early period, clawing it back through software licensing fees and the added value of a DVD player. Each Xbox lost over $100, and Microsoft absorbed $4 billion in losses \u2014 because its goal wasn't profit, it was blocking Sony (the story of Chapter Three)."}),"\n",(0,i.jsx)(n.p,{children:"Both rivals were trading losses for market share. And the cost of this war would only climb with every new generation. GPU performance doubled every two years. R&D costs doubled every two years. But game prices couldn't go up \u2014 consumers' psychological anchor for a game sat between $50 and $60, unchanged for a decade."}),"\n",(0,i.jsxs)(n.p,{children:["Iwata didn't need other companies' corpses to teach him arithmetic. GameCube's own failure was clear enough \u2014 Nintendo had fought its rivals spec for spec and sold the fewest units. And the industry's cost structure was right there on the page: ",(0,i.jsx)(n.strong,{children:"If Nintendo kept competing on compute power against Sony and Microsoft, it would either be crushed by costs or have to subsidize losses from a larger empire \u2014 but Nintendo had no Windows empire, and it had no patience from Wall Street."})," Sega's exit was corroborating evidence, not the cause. The real cause was the numbers on the calculator."]}),"\n",(0,i.jsx)(n.p,{children:"He made a decision that nearly every gaming outlet mocked at the time."}),"\n",(0,i.jsx)(n.p,{children:"Exit the performance race."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"iii-the-cost-of-not-fighting",children:"III. The Cost of Not Fighting"}),"\n",(0,i.jsx)(n.p,{children:"November 19, 2006 \u2014 two days after PS3 \u2014 the Wii launched in North America. $249."}),"\n",(0,i.jsx)(n.p,{children:"The Wii's hardware specs were treated as a joke in the gaming community. Its CPU was IBM's Broadway \u2014 essentially an overclocked version of GameCube's Gekko. Its GPU was ATI's Hollywood \u2014 an upgrade of GameCube's Flipper. The entire machine's performance was roughly a quarter to a third of the PS3 and Xbox 360."}),"\n",(0,i.jsx)(n.p,{children:"Sony's PS3 used the Cell Broadband Engine \u2014 a monster chip jointly developed by IBM, Sony, and Toshiba at an R&D cost exceeding $3 billion. Microsoft's Xbox 360 ran IBM's triple-core Xenon CPU paired with ATI's Xenos GPU \u2014 among the most advanced consumer graphics hardware of 2005."}),"\n",(0,i.jsx)(n.p,{children:"The Wii was running hardware from two generations ago."}),"\n",(0,i.jsx)(n.p,{children:"But the Wii did something the PS3 and Xbox 360 couldn't: it booted in two seconds and you could play. Its motion controller let a seventy-year-old grandmother play tennis. Its price point required no parental hesitation."}),"\n",(0,i.jsx)(n.p,{children:"Wii lifetime sales: 101.63 million. PS3: 87.4 million. Xbox 360: 85.8 million."}),"\n",(0,i.jsx)(n.p,{children:"Iwata won."}),"\n",(0,i.jsxs)(n.p,{children:["But we need to stop here and ask the question this book's readers should be in the habit of asking by now: ",(0,i.jsx)(n.strong,{children:"What was the cost?"})]}),"\n",(0,i.jsx)(n.p,{children:"The cost: Nintendo perfectly missed every piece of foundational technology accumulation on the road to AI supremacy."}),"\n",(0,i.jsx)(n.p,{children:"The Wii pushed no advanced semiconductor processes. Its chip used 90nm \u2014 90nm in 2006, the year Intel was already ramping 65nm production. The Wii's GPU had no programmable shader pipeline \u2014 the architectural innovation described in Chapter Seven that enabled NVIDIA to transform gaming GPUs into general-purpose compute platforms. The Wii was completely absent."}),"\n",(0,i.jsx)(n.p,{children:"The Wii contributed no large-die yield data to TSMC. It paid not a single cent of R&D tax into the CUDA ecosystem. Its existence, on the invisible supply chain from gaming to AI described in Chapters Seven and Eight, was a zero."}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Nintendo did not participate in forging the foundational infrastructure of AI supremacy."})," It withdrew from the arms race, preserved its finances, and in doing so permanently disconnected from the front line of humanity's push against technological limits."]}),"\n",(0,i.jsx)(n.p,{children:"This is not a moral judgment. It is a structural observation. Nintendo's choice let it survive \u2014 and surviving let it do something that, in the context of this book, is far more interesting."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"iv-the-island",children:"IV. The Island"}),"\n",(0,i.jsx)(n.p,{children:"While every other gaming giant was doing the same thing, Nintendo was doing the opposite."}),"\n",(0,i.jsxs)(n.p,{children:["Chapter Ten dissected that thing in detail: Microsoft gutting Xbox's studios and redirecting resources to AI infrastructure. Sony, under Jim Ryan's direction, forcing first-party studios to pivot to live-service games, shutting down Japan Studio, spending $200 million on a game \u2014 ",(0,i.jsx)(n.em,{children:"Concord"})," \u2014 that lasted fourteen days. Both companies followed the same logic: convert one-time transactions into recurring revenue. Pay Wall Street its protection money."]}),"\n",(0,i.jsx)(n.p,{children:"Nintendo didn't pay that protection money."}),"\n",(0,i.jsx)(n.p,{children:"The reason was simple \u2014 Nintendo is not a U.S.-listed company. It trades on the Tokyo Stock Exchange, with a shareholder base dominated by Japanese institutional investors and long-term holders. Wall Street's quarterly revenue pressure, the American public company's \"recurring revenue obsession\" \u2014 these carry far less weight in Nintendo's boardroom than in Microsoft's or Sony's."}),"\n",(0,i.jsx)(n.p,{children:"March 3, 2017. The Nintendo Switch launched. $299."}),"\n",(0,i.jsx)(n.p,{children:"The Switch's heart was NVIDIA's Tegra X1 \u2014 a mobile chip released in 2015. 20nm process. 256 CUDA cores. On the gaming hardware spectrum of 2017, its performance was roughly a quarter to a third of the PS4."}),"\n",(0,i.jsx)(n.p,{children:"Once again, the gaming press's first reaction was mockery."}),"\n",(0,i.jsx)(n.p,{children:"Once again, Nintendo won."}),"\n",(0,i.jsxs)(n.p,{children:["Switch cumulative sales exceeded 146 million units \u2014 surpassing the Wii to become the best-selling console in Nintendo's history. ",(0,i.jsx)(n.em,{children:"The Legend of Zelda: Breath of the Wild"}),". ",(0,i.jsx)(n.em,{children:"Animal Crossing"}),". ",(0,i.jsx)(n.em,{children:"Mario Kart 8"}),". These games didn't need ray tracing, didn't need 4K textures, didn't need 120 frames per second. They needed to be fun."]}),"\n",(0,i.jsx)(n.p,{children:"And throughout the Switch's entire lifecycle \u2014 2017 to 2024 \u2014 Nintendo stubbornly did several things that Microsoft and Sony did not:"}),"\n",(0,i.jsxs)(n.p,{children:['Its first-party games were sold as complete purchases. No season passes. No battle passes. No "pay \xa51,000 to unlock a limited-edition skin." You paid $60 for ',(0,i.jsx)(n.em,{children:"Breath of the Wild"}),", and you got a complete game."]}),"\n",(0,i.jsx)(n.p,{children:"It didn't close a single first-party studio. Didn't lay off thousands. Didn't cancel in-progress projects to dress up the balance sheet."}),"\n",(0,i.jsx)(n.p,{children:"It didn't force its studios to make live-service games. No Jim Ryan\u2013style company-wide pivot mandate."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"While Microsoft and Sony treated players as ATMs to subsidize R&D costs and treated studios as assets to be dismantled and reassembled at will, Nintendo did something that looked stupid \u2014 it treated players as customers."})}),"\n",(0,i.jsx)(n.p,{children:'But here we need to correct an illusion that might be forming: Nintendo is not an "open" company. Far from it.'}),"\n",(0,i.jsx)(n.p,{children:"In 1985 \u2014 a decade before DirectX, two decades before CUDA \u2014 Nintendo embedded a chip called 10NES in every licensed NES cartridge. When the console powered on, it performed a handshake authentication with the cartridge chip. Unauthorized cartridges got a black screen. This was the first hardware-level lock in the history of the gaming industry. The accompanying licensing regime was draconian: third-party developers faced annual title limits, mandatory exclusivity periods, and cartridges manufactured exclusively by Nintendo. From the NES to the Switch 2, every generation of Nintendo hardware has had its own proprietary cartridge or card format, its own authentication mechanism, its own closed developer program. From the NES through the 3DS, there was also hardware-level region locking."}),"\n",(0,i.jsxs)(n.p,{children:["Nintendo built the most stringent lock in the history of the gaming industry. But this lock had one characteristic that made it fundamentally different from every lock described in the preceding ten chapters: ",(0,i.jsx)(n.strong,{children:"It never spread outward."})]}),"\n",(0,i.jsx)(n.p,{children:"10NES didn't affect PCs. The Switch's closed ecosystem doesn't affect Steam. Nintendo never attempted to make its own technology the industry standard, never entered the DirectX vs. Vulkan standards wars. Its stance has never wavered: enter my garden, play by my rules. Don't want to come in? I don't care."}),"\n",(0,i.jsx)(n.p,{children:"In April 2026, someone got Steam running on a hacked original Switch \u2014 Valve's Proton had just added ARM64 support, and the Switch happened to use an ARM chip. Nintendo's response wasn't openness. It was fortifying the wall: the Switch 2 user agreement explicitly states that installing unauthorized software may result in permanent disabling of the entire console."}),"\n",(0,i.jsx)(n.p,{children:"Forty years ago, 10NES made unauthorized cartridges show a black screen. Forty years later, the countermeasure upgraded to account bans and remote bricking. The tools changed. The logic hasn't changed by a single word."}),"\n",(0,i.jsx)(n.p,{children:"Microsoft's DirectX is a weapon \u2014 a weapon for conquering the world outside. Nintendo's lock is a castle wall \u2014 for protecting the garden within. Both are locks. But one spreads outward. The other contracts inward."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"v-ns2-a-crack-in-the-island",children:"V. NS2: A Crack in the Island"}),"\n",(0,i.jsx)(n.p,{children:"But the story doesn't end here. Because on June 5, 2025, something happened that cracked a fissure in the \"Nintendo doesn't participate in the arms race\" narrative."}),"\n",(0,i.jsx)(n.p,{children:"The Nintendo Switch 2 launched. $449.99."}),"\n",(0,i.jsx)(n.p,{children:"The most expensive console in Nintendo's history. 50% more than the original Switch. Nearly double the Wii's $249 in 2006."}),"\n",(0,i.jsx)(n.p,{children:"More noteworthy was the chip inside."}),"\n",(0,i.jsx)(n.p,{children:"The Switch 2's heart is NVIDIA's custom Tegra T239 \u2014 codenamed Drake. This is not a chip born from \"withered technology.\" It's based on NVIDIA's Ampere architecture \u2014 the same architectural generation as the RTX 3080. 1,536 CUDA cores. RT cores for real-time ray tracing. Tensor cores \u2014 NVIDIA's dedicated AI compute units. Die area of 207 square millimeters \u2014 nearly twice the original Switch's Tegra X1. 12GB LPDDR5X memory."}),"\n",(0,i.jsx)(n.p,{children:"The chip's most critical feature is DLSS \u2014 Deep Learning Super Sampling. NVIDIA's AI upscaling technology. It allows the Switch 2 to render games at a lower native resolution, then use the Tensor cores' AI computation to \"upscale\" the image to 1080p or even 4K."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Inside Nintendo's new console, an NVIDIA AI chip is running."})}),"\n",(0,i.jsx)(n.p,{children:'BOM (bill of materials) estimates range from $330 to $400. If accurate, this means that Nintendo \u2014 a company whose iron rule has always been "hardware must be profitable" \u2014 may be operating on razor-thin margins or even losses on the Switch 2.'}),"\n",(0,i.jsx)(n.p,{children:"The T239 chip is fabricated by Samsung Foundry using Samsung's 8nm process (technically a derivative of its 10nm node) \u2014 the same process node used for NVIDIA's RTX 3090. Not TSMC."}),"\n",(0,i.jsxs)(n.p,{children:["Here a subtle but important fact emerges: ",(0,i.jsx)(n.strong,{children:"Nintendo's console chip orders did not enter TSMC's capacity pool."})," Chapters Eight and Ten emphasized that the long-term SoC orders from PS5 and Xbox Series X serve as ballast in TSMC's capacity planning. The Switch 2's orders went to Samsung \u2014 meaning that Nintendo's hardware existence is, once again, a zero on the \"console \u2192 TSMC \u2192 AI chip\" supply chain described in Chapter Eight. Even as it finally joined the compute race, it still hasn't stepped onto that track."]}),"\n",(0,i.jsx)(n.p,{children:"But the Switch 2 did something else."}),"\n",(0,i.jsx)(n.p,{children:"In its first four days, it sold 3.5 million units worldwide. The fastest launch in Nintendo's history. In 2025 \u2014 the year Microsoft's Xbox was being dismantled, the year Sony's first-party studios were drowning in the wreckage of live-service failures, the year the global gaming hardware market was supposedly shrinking \u2014 a $450 console, powered not by compute specs, not by an AI narrative, not by a recurring-revenue pitch for Wall Street, but by \"this machine has Mario and Zelda on it,\" sold 3.5 million in four days."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"While everyone else was dismantling games, only Nintendo was still making them. And consumers voted with their wallets for the one that was still making games."})}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"vi-closing-arguments",children:"VI. Closing Arguments"}),"\n",(0,i.jsxs)(n.p,{children:["In the preceding ten chapters, the pattern appeared eight times. Each variation took a different form \u2014 offensive, defensive, accidental, bidirectional lock-in \u2014 but the core logic was the same: ",(0,i.jsx)(n.strong,{children:"attract users with convenience, lock them in through dependency, turn users into appendages of the platform."})," And every lock shared one characteristic: it spread outward, penetrating platform boundaries, affecting the world beyond."]}),"\n",(0,i.jsx)(n.p,{children:"In this chapter, the pattern inverted."}),"\n",(0,i.jsx)(n.p,{children:"Sega didn't build a lock \u2014 it never lived long enough to lock down an ecosystem. Dreamcast's online service SegaNet had the embryo of lock-in, but PS2 killed it before it could take shape. Sega's exit was not a choice. It was a sentence."}),"\n",(0,i.jsx)(n.p,{children:"Nintendo built a lock \u2014 the earliest and most severe in gaming history. 10NES predated DirectX by a decade. But its lock was walled-garden type: boundaries ending at its own platform, never spreading outward, resetting to zero with each console generation. No one in 2025 is locked anywhere because of 1985's 10NES."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Three types of lock. Three outcomes."})}),"\n",(0,i.jsx)(n.p,{children:"Expansive lock-in \u2014 Microsoft, NVIDIA, TSMC, Valve \u2014 became the infrastructure of tech hegemony. Costs borne downstream. Deferred bills arriving two or three decades later."}),"\n",(0,i.jsx)(n.p,{children:"Walled-garden lock-in \u2014 Nintendo \u2014 survived for forty years, but remained irrelevant to the mainline of tech hegemony. A garden, not a supply chain."}),"\n",(0,i.jsx)(n.p,{children:"No lock \u2014 Sega \u2014 death."}),"\n",(0,i.jsx)(n.p,{children:"Nintendo chose. It chose not to participate in the compute arms race, from Wii to Switch, for eighteen years. It chose to draw the boundary of its lock at its own walls, never attempting to lock down the world beyond. That choice has two sides."}),"\n",(0,i.jsx)(n.p,{children:"One side is cost: Nintendo is absent from Chapter Seven's CUDA supply chain, absent from Chapter Eight's TSMC yield-testing crucible, absent from Chapter Nine's x86 vs. ARM architecture war. Its contribution to the foundational infrastructure of the AI revolution is zero. From the perspective of technology history, Nintendo's eighteen years have been a brilliant spectation."}),"\n",(0,i.jsxs)(n.p,{children:["The other side is reward: ",(0,i.jsx)(n.strong,{children:"Nintendo is the only company among all the characters in this book that, in 2025, still treats games as an end rather than a means."})," Microsoft treated games as a defensive weapon for Windows \u2014 used, then dismantled. Sony treated games as a revenue pipeline \u2014 reconfigured whenever the form didn't fit. NVIDIA treated gamers as R&D tax payers \u2014 once CUDA was fed, pivot to AI. TSMC treated gaming chips as stress tests for advanced nodes. Every company was exploiting games. Only Nintendo was still making them."]}),"\n",(0,i.jsx)(n.p,{children:"But the Switch 2 has broken something. $449. NVIDIA Ampere. DLSS. Tensor cores. For the first time, Nintendo put AI technology inside its console \u2014 not to do AI, but to let a handheld produce near-4K visuals. It's paying higher hardware costs now. It's drifting further from \"withered technology.\""}),"\n",(0,i.jsx)(n.p,{children:'Nintendo\'s island is being eroded by the tide. Not because Nintendo has changed \u2014 but because the hardware cost of "making a fun game console" in 2025 no longer allows anyone to stay independent on the cheap.'}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Sega died by being ahead of its time. Nintendo survived by being behind it. But the times are catching up."})}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"vii-the-spoils-are-still-being-divided",children:"VII. The Spoils Are Still Being Divided"}),"\n",(0,i.jsx)(n.p,{children:"In 2001, before exiting the console hardware market, Sega sold its NVIDIA shares. Bought for $5 million. Sold for $15 million. A triple return."}),"\n",(0,i.jsx)(n.p,{children:"In 2025, NVIDIA's market capitalization exceeded $5 trillion. That original $5 million investment, had it been held, would be worth tens of billions of dollars."}),"\n",(0,i.jsx)(n.p,{children:"Sega didn't wait for that day. It couldn't afford to."}),"\n",(0,i.jsx)(n.p,{children:"And Shoichiro Irimajiri \u2014 the man who, in 1996, made a decision that violated every business textbook and threw the last life preserver to NVIDIA \u2014 disappeared from public view after stepping down as Sega's president in 2000."}),"\n",(0,i.jsx)(n.p,{children:"Irimajiri never knew what he had done. He didn't know that $5 million would become the RIVA 128, then GeForce, then CUDA, then the H100, then a chokehold on the global AI industry. He just thought a young man deserved another chance."}),"\n",(0,i.jsx)(n.p,{children:"Sega is the purest character in this book. No conspiracies, no lock-in, no Wall Street numbers games. It pushed the frontier to make better games, gave generously out of principle, and exited to survive. Every one of its decisions was the decision a game maker would make \u2014 not a platform builder."}),"\n",(0,i.jsxs)(n.p,{children:["And Nintendo \u2014 the company that survived in the same market after Sega fell \u2014 is now facing a question Sega never lived long enough to confront: ",(0,i.jsx)(n.strong,{children:"As the cost of maintaining an island keeps rising, how long can you remain independent?"})]}),"\n",(0,i.jsx)(n.p,{children:"The Switch 2's $449 is already Nintendo's first concession to reality. What comes next? Next-gen consoles on TSMC's process? Joining the PS6 and next Xbox in a full compute arms race? Using DLSS 4.0 AI upscaling while still insisting on complete, one-time-purchase games?"}),"\n",(0,i.jsx)(n.p,{children:"No one knows."}),"\n",(0,i.jsx)(n.p,{children:"But one thing is certain. In the forty years recorded by this book, two companies proved something: you can refuse to participate in expansive platform lock-in, you can refuse to participate in the monopoly race, you can even refuse to participate in building the foundational infrastructure of AI hegemony."}),"\n",(0,i.jsx)(n.p,{children:"The cost is that you will never become a $5 trillion giant."}),"\n",(0,i.jsx)(n.p,{children:"The reward is that the thing you make is still a game."}),"\n",(0,i.jsx)(n.p,{children:'That is the question for the final chapter: after this forty-year sprint, how much are those four words \u2014 "still a game" \u2014 actually worth?'}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.img,{src:t(2020).A+"",width:"2816",height:"1536"})})]})}function c(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},2020(e,n,t){t.d(n,{A:()=>i});const i=t.p+"assets/images/ch11_en-672c5316d43ae269dbfebd39ce24d254.png"},8453(e,n,t){t.d(n,{R:()=>s,x:()=>r});var i=t(6540);const a={},o=i.createContext(a);function s(e){const n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);